// Verify Posta's HMAC signature over `{timestamp}.{rawBody}` (constant-time),
// then emit the parsed payload. Throws (stops the run) if verification fails.
const crypto = require('crypto');
const item = $input.first();
const headers = item.json.headers || {};
const sig = headers['x-posta-signature'];
const ts = headers['x-posta-timestamp'];
if (!sig || !ts) throw new Error('Missing X-Posta-Signature / X-Posta-Timestamp');

// Raw body (the Webhook node has Raw Body enabled -> binary 'data').
const raw = item.binary && item.binary.data
  ? Buffer.from(item.binary.data, 'base64').toString('utf8')
  : JSON.stringify(item.json.body);

const secret = $env.POSTA_WEBHOOK_SECRET;
if (!secret) throw new Error('Set POSTA_WEBHOOK_SECRET in n8n env');

const expected = crypto.createHmac('sha256', secret).update(`${ts}.${raw}`).digest('hex');
const a = Buffer.from(sig);
const b = Buffer.from(expected);
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  throw new Error('Bad signature');
}
return [{ json: JSON.parse(raw) }];

